def clamp(value, low, high):
    if value < low:
        return low
    if value > high:
        return high
    return value

def initials(full_name):
    parts = full_name.split()
    return parts[0][0].upper() + "." + parts[1][0].upper() + "."

def progress(done, total):
    if total == 0:
        return 0
    return done / total * 100

